mapper.select:
/* on.standard.system.menu.selectMenuByUrl */ SELECT SMMH.MENU_DIV_CD , SMMH.MENU_SERNO , SMMH.MENU_CD , SMMH.UPR_MENU_CD , SMMH.MENU_CL , SMMH.KOR_NM , SMMH.MENU_PARAM , SMMH.LAY_OUT , SMMH.RTN_URL , SMMH.URL_ADDR , SMMH.SORT_NO , SMMH.USE_YN , SMMH.LEVEL , SMMH.SORT_PATH , SMMH.MENU_PATH , SMMH.MENU_CD_PATH FROM SVI_MENU_MNG_HIERARCHY SMMH WHERE SMMH.URL_ADDR = #{pageUrl}
AND SMMH.MENU_FUNC_DIV = #{menuFUncDivCd}
AND SMMH.MENU_FUNC_CD = #{menuFuncCd}

/* on.standard.system.menu.selectMenuPermissionCheck */ SELECT MM.MENU_DIV_CD , MM.MENU_CD , MM.URL_ADDR , MM.MENU_PARAM , MM.KOR_NM , AUM.USER_ID , MM.MENU_PATH , MM.MENU_CD_PATH , MAX(MAM.USE_YN) USE_YN , MAX(MAM.READ_YN) READ_YN , MAX(MAM.WRITE_YN) WRITE_YN , MAX(MAM.UPDATE_YN) UPDATE_YN , MAX(MAM.DELETE_YN) DELETE_YN , MAX(MAM.POPUP_OPEN_YN) POPUP_OPEN_YN , MAX(MAM.POPUP_READ_YN) POPUP_READ_YN , MAX(MAM.POPUP_WRITE_YN) POPUP_WRITE_YN , MAX(MAM.POPUP_UPDATE_YN) POPUP_UPDATE_YN , MAX(MAM.POPUP_DELETE_YN) POPUP_DELETE_YN FROM SVI_MENU_MNG_HIERARCHY MM INNER JOIN STB_M_MENU_AUTH_MNG MAM on MM.MENU_CD = MAM.MENU_CD INNER JOIN STB_M_AUTH_USER_MNG AUM on MAM.AUTH_ID = AUM.AUTH_ID WHERE MM.URL_ADDR = #{urlAddr} AND AUM.USER_ID = #{loginUserId}
AND MM.MENU_FUNC_DIV = #{menuFUncDivCd}
AND MM.MENU_FUNC_CD = #{menuFuncCd}
GROUP BY MM.MENU_DIV_CD, MM.MENU_CD, MM.URL_ADDR, MM.MENU_PARAM, MM.KOR_NM, AUM.USER_ID, MM.MENU_PATH, MM.MENU_CD_PATH

/* on.standard.system.menu.selectLeftMenus */ SELECT DISTINCT SMMH.LEVEL AS level , SMMH.MENU_CD AS menuCd , SMMH.UPR_MENU_CD AS uprMenuCd , SMMH.KOR_NM AS korNm , SMMH.MENU_CL AS menuCl , SMMH.MENU_FUNC_DIV AS menuFuncDiv , SMMH.MENU_FUNC_CD AS menuFuncCd , SMMH.URL_ADDR AS urlAddr , SMMH.MENU_PARAM AS menuParam , SMMH.MENU_CSS AS menuCss , SMMH.MENU_TARGET AS menuTarget , SMMH.MENU_PATH AS menuPath , SMMH.IS_LEAF AS isLeaf , CASE WHEN EXISTS ( SELECT 1 FROM SVI_MENU_MNG_HIERARCHY X WHERE X.URL_ADDR = #{pageUrl}
AND X.MENU_FUNC_DIV = #{menuFuncDivCd}
AND X.MENU_FUNC_CD = #{menuFuncCd}
AND X.MENU_PATH LIKE CONCAT(SMMH.MENU_PATH, '%') ) THEN 'on' ELSE '' END AS menuFocus FROM SVI_MENU_MNG_HIERARCHY SMMH INNER JOIN STB_M_MENU_AUTH_MNG MMAM ON SMMH.MENU_CD = MMAM.MENU_CD AND MMAM.USE_YN = 'Y' WHERE MMAM.AUTH_ID IN ( SELECT AUTH_ID FROM STB_M_AUTH_USER_MNG SMAUM WHERE USER_ID = #{loginUserId} AND USE_YN = 'Y' ) AND SMMH.USE_YN = 'Y' AND SMMH.MENU_DIV_CD = 'MA' AND SMMH.MENU_CL IN ('MAIN') ORDER BY SMMH.LEVEL, SMMH.SORT_PATH

mapper.insert:
/* on.standard.system.menu.mergeInsMenuInfo */
INSERT INTO STB_B_MENU_MNG (
         MENU_DIV_CD
       , MENU_CD
       , UPR_MENU_CD
       , KOR_NM
       , ENG_NM
       , MENU_CL
       , MENU_PARAM
       , MENU_TARGET
       , LAY_OUT
       , MENU_CSS
       , URL_ADDR
       , RTN_URL
       , SORT_NO
       , MENU_COMMENT
       , MENU_FUNC_DIV
       , MENU_FUNC_CD
       , USE_YN
       , REG_USER
       , REG_DATE
) VALUES (
           #{menuDivCd}
         , #{menuCd}
         , COALESCE(NULLIF(#{uprMenuCd}, ''), '00000000')
         , #{korNm}
         , #{engNm}
         , #{menuCl}
         , #{menuParam}
         , #{menuTarget}
         , #{menuLayout}   /* 기본 레이아웃 */
         , #{menuCss}
         , #{urlAddr}
         , #{rtnUrl}
         , #{sortNo}
         , #{menuComment}
         , #{menuFuncDiv}
         , #{menuFuncCd}
         , #{useYn}
         , #{loginUserId}
         , NOW()
         )
    ON DUPLICATE KEY UPDATE
       UPR_MENU_CD  = COALESCE(NULLIF(#{uprMenuCd}, ''), '00000000')
     , KOR_NM       = #{korNm}
     , ENG_NM       = #{engNm}
     , MENU_CL      = #{menuCl}
     , MENU_PARAM   = #{menuParam}
     , MENU_TARGET  = #{menuTarget}
     , LAY_OUT      = #{menuLayout}
     , MENU_CSS     = #{menuCss}
     , URL_ADDR     = #{urlAddr}
     , RTN_URL      = #{rtnUrl}
     , SORT_NO      = #{sortNo}
     , MENU_COMMENT = #{menuComment}
     , MENU_FUNC_DIV = #{menuFuncDiv}
     , MENU_FUNC_CD  = #{menuFuncCd}
     , USE_YN       = #{useYn}

mapper.delete:
/* on.standard.system.menu.delMenuInfo */
DELETE FROM STB_B_MENU_MNG
  WHERE MENU_CD = #{menuCd}
